            var filtro = new FilterProSucumbencia
            {
                TipoOrigemSucumbencia = valorTipoOrigemSucumbenciaInicial,
                TipoOrigemSucumbencia_end = valorTipoOrigemSucumbenciaFinal,
                LogicalOperator = " AND "
            };
            // Act
            var resultado = _serviceS.WFiltro(filtro);
            // Assert
            resultado.Should().NotBeNull();
            // Deve usar operador BETWEEN
            resultado.Value.where.Should().Contain($"[{DBProSucumbenciaDicInfo.PTabelaNome}].{DBProSucumbenciaDicInfo.TipoOrigemSucumbencia} BETWEEN @{DBProSucumbenciaDicInfo.TipoOrigemSucumbencia} AND @{DBProSucumbenciaDicInfo.TipoOrigemSucumbencia}_end");
            resultado.Value.where.Should().NotContain(" = ");
