            ((DateTime)parameter.Value).Should().Be(expectedDate);
            result.Value.where.Should().Contain($"CONVERT(DATE,[{DBProSucumbenciaDicInfo.PTabelaNome}].[{DBProSucumbenciaDicInfo.DtCad}], 103) = CONVERT(DATE, @{DBProSucumbenciaDicInfo.DtCad}, 103)");
