            endParameter!.Value.Should().BeOfType<DateTime>();
            ((DateTime)startParameter.Value).Should().Be(DateTime.Parse(startDate));
            ((DateTime)endParameter.Value).Should().Be(DateTime.Parse(endDate));
            result.Value.where.Should().Contain($"[{DBProSucumbenciaDicInfo.PTabelaNome}].{DBProSucumbenciaDicInfo.Data} BETWEEN @{DBProSucumbenciaDicInfo.Data} AND @{DBProSucumbenciaDicInfo.Data}_end");
        }

